changeSet.sql:
ALTER TABLE nexus.chunks_384             VALIDATE CONSTRAINT chunks_384_chash_len_check;
ALTER TABLE nexus.chunks_768             VALIDATE CONSTRAINT chunks_768_chash_len_check;
ALTER TABLE nexus.chunks_1024            VALIDATE CONSTRAINT chunks_1024_chash_len_check;
ALTER TABLE nexus.catalog_document_chunks VALIDATE CONSTRAINT catalog_document_chunks_chash_len_check;
ALTER TABLE nexus.chash_index            VALIDATE CONSTRAINT chash_index_chash_len_check;

-- INCIDENT nexus-4m6i0.1 (2026-07-09, ms57z / GH#1390): engine-service v0.1.36
-- crash-looped on boot. Root cause: catalog-013-2's five bare VALIDATE CONSTRAINT
-- statements run as one atomic changeset; on an aged/divergent box where ANY one
-- of the five constraints is missing (confirmed: chunks_384_chash_len_check absent
-- on an empty/never-populated bge-768-only box), Postgres raises a hard ERROR and
-- the whole migration aborts, over and over, every restart.
--
-- Investigated and CLOSED as a dead end: "ADD CONSTRAINT was conditional/skipped
-- for empty dim tables" is FALSE — catalog-002-hygiene.xml's catalog-002-2-chash-
-- checks changeset adds all five unconditionally (verified against commit
-- 34c23773 / tag engine-service-v0.1.29). However the divergence actually arose
-- on the real box, it is out-of-band and not chased further here (tracked
-- separately, non-blocking); this changeset is defensive regardless of cause.
--
-- Each guard below is INDEPENDENT: any subset of the five constraints may be
-- missing on a given box and every OTHER constraint still gets validated. This
-- changeset does not edit catalog-013-2's checksummed SQL body in place (already
-- shipped in engine-service-v0.1.33 through v0.1.36) — it is a NEW changeset
-- that re-does 013-2's validation defensively, following the same precedent as
-- catalog-013-1b (new changeset id + new author, original changesets untouched).
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chunks_384_chash_len_check') THEN
        ALTER TABLE nexus.chunks_384 VALIDATE CONSTRAINT chunks_384_chash_len_check;
    END IF;
END $$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chunks_768_chash_len_check') THEN
        ALTER TABLE nexus.chunks_768 VALIDATE CONSTRAINT chunks_768_chash_len_check;
    END IF;
END $$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chunks_1024_chash_len_check') THEN
        ALTER TABLE nexus.chunks_1024 VALIDATE CONSTRAINT chunks_1024_chash_len_check;
    END IF;
END $$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'catalog_document_chunks_chash_len_check') THEN
        ALTER TABLE nexus.catalog_document_chunks VALIDATE CONSTRAINT catalog_document_chunks_chash_len_check;
    END IF;
END $$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chash_index_chash_len_check') THEN
        ALTER TABLE nexus.chash_index VALIDATE CONSTRAINT chash_index_chash_len_check;
    END IF;
END $$;
